namespace Tianyou.Api.Middleware;

/// <summary>
/// 请求日志中间件 - 记录所有HTTP请求和响应
/// </summary>
public class RequestLoggingMiddleware
{
    private readonly RequestDelegate _next;
    private readonly ILogger<RequestLoggingMiddleware> _logger;

    public RequestLoggingMiddleware(RequestDelegate next, ILogger<RequestLoggingMiddleware> logger)
    {
        _next = next;
        _logger = logger;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var startTime = DateTime.UtcNow;
        var requestId = Guid.NewGuid().ToString();

        // 记录请求信息
        var requestInfo = new
        {
            RequestId = requestId,
            Method = context.Request.Method,
            Path = context.Request.Path.Value,
            QueryString = context.Request.QueryString.Value,
            UserAgent = context.Request.Headers["User-Agent"].ToString(),
            RemoteIpAddress = context.Connection.RemoteIpAddress?.ToString(),
            UserId = context.User?.Identity?.Name ?? "Anonymous",
            Timestamp = startTime
        };

        // 记录请求开始
        Log.Information("HTTP Request Started: {@RequestInfo}", requestInfo);

        // 保存原始响应流
        var originalBodyStream = context.Response.Body;
        using var responseBody = new MemoryStream();
        context.Response.Body = responseBody;

        try
        {
            await _next(context);

            var duration = (DateTime.UtcNow - startTime).TotalMilliseconds;

            // 记录响应信息
            var responseInfo = new
            {
                RequestId = requestId,
                StatusCode = context.Response.StatusCode,
                Duration = duration,
                ContentType = context.Response.ContentType,
                Timestamp = DateTime.UtcNow
            };

            // 根据状态码选择日志级别
            var logLevel = context.Response.StatusCode switch
            {
                >= 500 => LogEventLevel.Error,
                >= 400 => LogEventLevel.Warning,
                _ => LogEventLevel.Information
            };

            Log.Write(logLevel, "HTTP Request Completed: {@ResponseInfo}", responseInfo);

            // 复制响应数据到原始流
            responseBody.Seek(0, SeekOrigin.Begin);
            await responseBody.CopyToAsync(originalBodyStream);
        }
        catch (Exception ex)
        {
            var duration = (DateTime.UtcNow - startTime).TotalMilliseconds;

            // 记录异常信息
            Log.Error(ex, "HTTP Request Failed: {@ErrorInfo}", new
            {
                RequestId = requestId,
                Method = context.Request.Method,
                Path = context.Request.Path.Value,
                Duration = duration,
                Exception = ex.Message,
                StackTrace = ex.StackTrace
            });

            // 重新抛出异常
            throw;
        }
        finally
        {
            context.Response.Body = originalBodyStream;
        }
    }
}

/// <summary>
/// 审计日志中间件 - 记录关键业务操作
/// </summary>
public class AuditLoggingMiddleware
{
    private readonly RequestDelegate _next;
    private readonly ILogger<AuditLoggingMiddleware> _logger;

    // 需要审计的API路径
    private static readonly string[] AuditPaths = new[]
    {
        "/api/auth/login",
        "/api/auth/register",
        "/api/auth/change-password",
        "/api/entities/",
        "/api/forms/",
        "/api/workflows/",
        "/api/users/",
        "/api/roles/",
        "/api/permissions/"
    };

    public AuditLoggingMiddleware(RequestDelegate next, ILogger<AuditLoggingMiddleware> logger)
    {
        _next = next;
        _logger = logger;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var path = context.Request.Path.Value ?? "";

        // 检查是否需要审计
        var requiresAudit = AuditPaths.Any(auditPath => 
            path.StartsWith(auditPath, StringComparison.OrdinalIgnoreCase)) &&
            context.Request.Method != "GET";

        if (!requiresAudit)
        {
            await _next(context);
            return;
        }

        var startTime = DateTime.UtcNow;
        var auditId = Guid.NewGuid().ToString();

        // 读取请求体
        string requestBody = "";
        if (context.Request.ContentLength > 0 && context.Request.Body.CanRead)
        {
            using var reader = new StreamReader(context.Request.Body, leaveOpen: true);
            requestBody = await reader.ReadToEndAsync();
            context.Request.Body.Position = 0;
        }

        // 记录审计日志（开始）
        var auditInfo = new
        {
            AuditId = auditId,
            Action = context.Request.Method,
            Path = path,
            QueryString = context.Request.QueryString.Value,
            UserId = context.User?.Identity?.Name ?? "Anonymous",
            UserIp = context.Connection.RemoteIpAddress?.ToString(),
            RequestBody = TruncateBody(requestBody),
            Timestamp = startTime
        };

        Log.Information("Audit Log - Action Started: {@AuditInfo}", auditInfo);

        try
        {
            await _next(context);

            var duration = (DateTime.UtcNow - startTime).TotalMilliseconds;

            // 记录审计日志（完成）
            var auditResult = new
            {
                AuditId = auditId,
                Action = context.Request.Method,
                Path = path,
                StatusCode = context.Response.StatusCode,
                Duration = duration,
                Success = context.Response.StatusCode < 400,
                Timestamp = DateTime.UtcNow
            };

            Log.Information("Audit Log - Action Completed: {@AuditResult}", auditResult);
        }
        catch (Exception ex)
        {
            var duration = (DateTime.UtcNow - startTime).TotalMilliseconds;

            // 记录审计日志（失败）
            var auditError = new
            {
                AuditId = auditId,
                Action = context.Request.Method,
                Path = path,
                Duration = duration,
                Success = false,
                Error = ex.Message,
                Timestamp = DateTime.UtcNow
            };

            Log.Error(ex, "Audit Log - Action Failed: {@AuditError}", auditError);

            throw;
        }
    }

    private string TruncateBody(string body, int maxLength = 1000)
    {
        if (string.IsNullOrEmpty(body) || body.Length <= maxLength)
            return body;

        return body.Substring(0, maxLength) + "...[truncated]";
    }
}

/// <summary>
/// 中间件扩展方法
/// </summary>
public static class LoggingMiddlewareExtensions
{
    public static IApplicationBuilder UseRequestLogging(this IApplicationBuilder builder)
    {
        return builder.UseMiddleware<RequestLoggingMiddleware>();
    }

    public static IApplicationBuilder UseAuditLogging(this IApplicationBuilder builder)
    {
        return builder.UseMiddleware<AuditLoggingMiddleware>();
    }
}

using Serilog;
using Serilog.Events;
using Serilog.Sinks.Elasticsearch;
using System.Reflection;

namespace Tianyou.Api.Extensions;

/// <summary>
/// Serilog 配置扩展
/// </summary>
public static class SerilogExtensions
{
    /// <summary>
    /// 配置 Serilog 日志系统
    /// </summary>
    public static WebApplicationBuilder ConfigureSerilog(this WebApplicationBuilder builder)
    {
        var configuration = builder.Configuration;
        var environment = builder.Environment;

        // 创建 Serilog Logger
        var logger = new LoggerConfiguration()
            .ReadFrom.Configuration(configuration)
            .Enrich.FromLogContext()
            .Enrich.WithMachineName()
            .Enrich.WithEnvironmentUserName()
            .Enrich.WithThreadId()
            .Enrich.WithProperty("Application", "Tianyou API")
            .Enrich.WithProperty("Environment", environment.EnvironmentName)
            .Enrich.WithProperty("Version", Assembly.GetExecutingAssembly().GetName().Version?.ToString() ?? "1.0.0")

            // 控制台输出
            .WriteTo.Console(
                outputTemplate: "[{Timestamp:HH:mm:ss} {Level:u3}] {Message:lj} {Properties:j}{NewLine}{Exception}"
            )

            // 文件输出（滚动日志）
            .WriteTo.File(
                path: "logs/tianyou-.log",
                rollingInterval: RollingInterval.Day,
                retainedFileCountLimit: 30,
                outputTemplate: "{Timestamp:yyyy-MM-dd HH:mm:ss.fff zzz} [{Level:u3}] {Message:lj} {Properties:j}{NewLine}{Exception}",
                restrictedToMinimumLevel: LogEventLevel.Information
            )

            // 错误日志单独文件
            .WriteTo.File(
                path: "logs/errors/tianyou-errors-.log",
                rollingInterval: RollingInterval.Day,
                retainedFileCountLimit: 90,
                outputTemplate: "{Timestamp:yyyy-MM-dd HH:mm:ss.fff zzz} [{Level:u3}] {Message:lj} {Properties:j}{NewLine}{Exception}",
                restrictedToMinimumLevel: LogEventLevel.Error
            );

        // Seq 日志服务器（如果配置）
        var seqServerUrl = configuration["Serilog:Seq:ServerUrl"];
        if (!string.IsNullOrEmpty(seqServerUrl))
        {
            logger.WriteTo.Seq(
                serverUrl: seqServerUrl,
                apiKey: configuration["Serilog:Seq:ApiKey"],
                restrictedToMinimumLevel: LogEventLevel.Information
            );
        }

        // Elasticsearch 日志（如果配置）
        var elasticsearchUrl = configuration["Serilog:Elasticsearch:Url"];
        if (!string.IsNullOrEmpty(elasticsearchUrl))
        {
            logger.WriteTo.Elasticsearch(new ElasticsearchSinkOptions(new Uri(elasticsearchUrl))
            {
                AutoRegisterTemplate = true,
                AutoRegisterTemplateVersion = AutoRegisterTemplateVersion.ESv7,
                IndexFormat = $"tianyou-logs-{environment.EnvironmentName.ToLower()}-{DateTime.UtcNow:yyyy-MM}",
                MinimumLogEventLevel = LogEventLevel.Information,
                EmitEventFailure = EmitEventFailureHandling.WriteToSelfLog,
                BatchAction = ElasticOpType.Create
            });
        }

        // 创建 Logger
        Log.Logger = logger.CreateLogger();

        // 使用 Serilog
        builder.Host.UseSerilog();

        return builder;
    }

    /// <summary>
    /// 添加请求日志中间件
    /// </summary>
    public static WebApplication UseRequestLoggingMiddleware(this WebApplication app)
    {
        // 使用 Serilog 请求日志中间件
        app.UseSerilogRequestLogging(options =>
        {
            options.MessageTemplate = "HTTP {RequestMethod} {RequestPath} responded {StatusCode} in {Elapsed:0.0000} ms";
            options.EnrichDiagnosticContext = (diagnosticContext, httpContext) =>
            {
                diagnosticContext.Set("RequestHost", httpContext.Request.Host.Value);
                diagnosticContext.Set("RequestScheme", httpContext.Request.Scheme);
                diagnosticContext.Set("RemoteIpAddress", httpContext.Connection.RemoteIpAddress?.ToString());
                diagnosticContext.Set("UserId", httpContext.User?.Identity?.Name ?? "Anonymous");
                diagnosticContext.Set("UserAgent", httpContext.Request.Headers["User-Agent"].ToString());
            };
        });

        return app;
    }
}

