# ==================== Logstash Pipeline 配置 ====================
# 天佑平台日志处理管道
# 作者：兵部
# 日期：2026-03-25

input {
  # Beats 输入（接收 Filebeat 日志）
  beats {
    port => 5044
    host => "0.0.0.0"
  }

  # HTTP 输入（接收应用直接发送的日志）
  http {
    port => 9600
    host => "0.0.0.0"
    codec => json
  }

  # TCP 输入（接收 Serilog 日志）
  tcp {
    port => 5000
    codec => json_lines
  }
}

filter {
  # 解析 JSON 日志
  if [message] =~ /^\{/ {
    json {
      source => "message"
      target => "parsed"
    }
  }

  # 解析时间戳
  date {
    match => [ "timestamp", "ISO8601", "yyyy-MM-dd HH:mm:ss.SSS" ]
    target => "@timestamp"
    timezone => "Asia/Shanghai"
  }

  # 提取日志级别
  if [parsed][level] {
    mutate {
      rename => { "[parsed][level]" => "log_level" }
    }
  }

  # 提取应用信息
  if [parsed][Properties][Application] {
    mutate {
      add_field => { "application" => "%{[parsed][Properties][Application]}" }
    }
  }

  # 提取环境信息
  if [parsed][Properties][Environment] {
    mutate {
      add_field => { "environment" => "%{[parsed][Properties][Environment]}" }
    }
  }

  # 提取用户信息
  if [parsed][Properties][UserId] {
    mutate {
      add_field => { "user_id" => "%{[parsed][Properties][UserId]}" }
    }
  }

  # 提取请求信息
  if [parsed][Properties][RequestId] {
    mutate {
      add_field => { "request_id" => "%{[parsed][Properties][RequestId]}" }
    }
  }

  # 提取审计信息
  if [parsed][Properties][AuditId] {
    mutate {
      add_field => { "audit_id" => "%{[parsed][Properties][AuditId]}" }
      add_tag => [ "audit" ]
    }
  }

  # 解析 HTTP 请求日志
  if [parsed][MessageTemplate] =~ "HTTP.*responded" {
    grok {
      match => { "[parsed][message]" => "HTTP %{WORD:method} %{DATA:path} responded %{NUMBER:status} in %{NUMBER:duration} ms" }
    }
    mutate {
      add_tag => [ "http_request" ]
      convert => { "status" => "integer" }
      convert => { "duration" => "float" }
    }
  }

  # 标记错误日志
  if [log_level] in ["Error", "Fatal", "Critical"] {
    mutate {
      add_tag => [ "error" ]
    }
  }

  # 标记警告日志
  if [log_level] == "Warning" {
    mutate {
      add_tag => [ "warning" ]
    }
  }

  # 标记审计日志
  if [parsed][MessageTemplate] =~ "Audit Log" {
    mutate {
      add_tag => [ "audit" ]
    }
  }

  # 移除不需要的字段
  mutate {
    remove_field => [ "host", "@version" ]
  }
}

output {
  # Elasticsearch 输出
  elasticsearch {
    hosts => ["http://elasticsearch:9200"]
    index => "tianyou-logs-%{[environment]}-%{+YYYY.MM.dd}"
    template_name => "tianyou-logs"
    template_overwrite => true
  }

  # 调试输出（生产环境可注释掉）
